            if (attempt > 0) {
                Log.d("WhisperService", "Retry $attempt/$MAX_RETRIES")
                kotlinx.coroutines.delay(2000L * attempt) // 递增延迟
            }

            val result = transcribeGroqInternal(audioFile, config, lang)
            if (result?.success == true) {
                return result
            }
            lastError = Exception(result?.error ?: "Unknown error")
        }

        // 所有重试都失败
        return WhisperResult(
            success = false,
            error = "❌ 转录失败（已重试 $MAX_RETRIES 次）\n\n${lastError?.message ?: "未知错误"}\n\n建议：检查网络连接和 API Key 配置"
        )
    }

    /**
     * 检查是否是速率限制错误（429）
     * 从错误消息中提取需要等待的时间（秒）
     */
    fun isRateLimitError(errorMsg: String): Pair<Boolean, Int> {
        val rateLimitPattern = Regex("Please try again in (\\d+)s")
        val match = rateLimitPattern.find(errorMsg)
        return if (match != null) {
            val seconds = match.groupValues[1].toIntOrNull() ?: 0
            Pair(true, seconds)
        } else {
            Pair(false, 0)
        }
    }

