    contextPrompt: String? = null
): WhisperResult? = withContext(Dispatchers.IO) {
    var lastResult: WhisperResult? = null
    var actualAttempts = 0
    val maxAttempts = MAX_RETRIES + 2  // 额外允许2次429重试

    while (actualAttempts < maxAttempts) {
        if (actualAttempts > 0) {
            Log.d(TAG, "Retrying segment $segmentIndex transcription, attempt $actualAttempts")
        }

        val result = whisperService.transcribeGroq(segmentFile, config, lang, contextPrompt)
        if (result?.success == true) {
            delay(API_REQUEST_INTERVAL_MS)
            return@withContext result
        }

        // 检查是否是速率限制错误（429）- 等待API指定时间后重试，不计入常规重试
        if (result?.error?.contains("Rate limit", ignoreCase = true) == true ||
            result?.error?.contains("rate_limit", ignoreCase = true) == true) {
            val isRateLimit = whisperService.isRateLimitError(result.error)
            val waitSeconds = if (isRateLimit.first && isRateLimit.second > 0) {
                isRateLimit.second + 2  // 多等2秒确保配额恢复
            } else {
                30  // 默认等30秒
            }
            Log.w(TAG, "Rate limit on segment $segmentIndex, waiting ${waitSeconds}s before retry")
            delay(waitSeconds * 1000L)
            actualAttempts++
            continue
        }

        // 非429错误，正常重试
        actualAttempts++
        if (actualAttempts < maxAttempts) {
            delay(RETRY_DELAY_BASE_MS * actualAttempts)
        }
        lastResult = result
    }

    Log.e(TAG, "Segment $segmentIndex transcription failed after $actualAttempts attempts")
    lastResult
}

