539→@Composable
540→fun DictationPanel(
541→    subtitle: SubtitleCue?,
542→    onSpeak: (String) -> Unit,
543→    onNext: () -> Unit,
544→    onLookup: (String) -> Unit
545→) {
546→    if (subtitle == null) {
547→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
548→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
549→        }
550→        return
551→    }
552→
553→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
554→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
555→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
556→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
557→
558→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
559→        // Word input boxes
560→        Card(modifier = Modifier.fillMaxWidth()) {
561→            Column(modifier = Modifier.padding(16.dp)) {
562→                Row(
563→                    modifier = Modifier.fillMaxWidth(),
564→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
565→                    verticalAlignment = Alignment.CenterVertically
566→                ) {
567→                    words.forEachIndexed { i, word ->
568→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
569→                            OutlinedTextField(
570→                                value = inputs[i],
571→                                onValueChange = { inputs[i] = it },
572→                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
573→                                singleLine = true,
574→                                isError = results[i] == "wrong",
575→                                colors = OutlinedTextFieldDefaults.colors(
576→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
577→                                )
578→                            )
579→                            if (results[i] == "wrong") {
580→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
581→                            }
582→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
583→                                Text("查词", style = MaterialTheme.typography.labelSmall)
584→                            }
585→                        }
586→                    }
587→                }
588→            }
589→        }
590→
591→        Spacer(Modifier.height(12.dp))
592→
593→        // Control buttons
594→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
595→            Button(onClick = { onSpeak(subtitle.text) }) {
596→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
597→                Spacer(Modifier.width(4.dp))
598→                Text("朗读")
599→            }
600→            Button(onClick = {
601→                answers.forEachIndexed { i, answer ->
602→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
603→                }
604→            }) {
605→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
606→                Spacer(Modifier.width(4.dp))
607→                Text("检查")
608→            }
609→            Button(onClick = {
610→                inputs.indices.forEach { inputs[it] = "" }
611→                results.indices.forEach { results[it] = "" }
612→                onNext()
613→            }) {
614→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
615→                Spacer(Modifier.width(4.dp))
616→                Text("下一句")
617→            }
618→        }
619→    }
620→}
