    /**
     * 打开应用文件夹（视频下载目录）
     */
    fun openFileLocation(filePath: String, context: Context) {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                val videoFile = File(filePath)
                if (!videoFile.exists()) {
                    withContext(Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "文件不存在", android.widget.Toast.LENGTH_SHORT).show()
                    }
                    return@launch
                }

                val parentDir = videoFile.parentFile ?: return@launch

                withContext(Dispatchers.Main) {
                    var opened = false

                    // 方式1：用 DocumentsUI 打开目录（兼容性最好）
                    if (!opened) {
                        try {
                            val relativePath = parentDir.absolutePath.removePrefix("/storage/emulated/0/")
                            val encodedPath = android.net.Uri.encode(relativePath, "/")
                            val uri = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:$encodedPath")
                            val intent = Intent(Intent.ACTION_VIEW).apply {
                                setDataAndType(uri, "vnd.android.document/directory")
                                addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                            }
                            context.startActivity(intent)
                            opened = true
                        } catch (_: Exception) {}
                    }

                    // 方式2：用系统文件管理器 BROWSE 动作
                    if (!opened) {
                        try {
                            val intent = Intent("android.provider.action.BROWSE").apply {
                                data = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:${parentDir.absolutePath.removePrefix("/storage/emulated/0/")}")
                                addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                            }
                            context.startActivity(intent)
                            opened = true
                        } catch (_: Exception) {}
                    }

                    // 方式3：直接分享视频文件
                    if (!opened) {
                        try {
                            val uri = androidx.core.content.FileProvider.getUriForFile(
                                context, "${context.packageName}.fileprovider", videoFile
                            )
                            val intent = Intent(Intent.ACTION_VIEW).apply {
                                setDataAndType(uri, "video/*")
                                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
                                addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                            }
                            context.startActivity(Intent.createChooser(intent, "打开视频文件"))
                            opened = true
                        } catch (_: Exception) {}
                    }

                    // 兜底：复制路径到剪贴板
                    if (!opened) {
                        val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                        clipboard.setPrimaryClip(android.content.ClipData.newPlainText("文件路径", parentDir.absolutePath))
                        android.widget.Toast.makeText(
                            context,
                            "已复制文件夹路径: ${parentDir.absolutePath}",
                            android.widget.Toast.LENGTH_LONG
                        ).show()
                    }
                }
            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Error opening file", e)
                withContext(Dispatchers.Main) {
                    android.widget.Toast.makeText(context, "打开失败: ${e.message}", android.widget.Toast.LENGTH_LONG).show()
                }
            }
        }
    }

